  defaultAccount?: string;
};

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    irc?: IrcConfig;
  };
};

export type IrcInboundMessage = {
  messageId: string;
  /** Conversation peer id: channel name for groups, sender nick for DMs. */
  target: string;
  /** Raw IRC PRIVMSG target (bot nick for DMs, channel for groups). */
  rawTarget?: string;
  senderNick: string;
  senderUser?: string;
  senderHost?: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

export type IrcProbe = BaseProbeResult<string> & {
  host: string;
  port: number;
  tls: boolean;
  nick: string;
  latencyMs?: number;
};
```

**Type Hierarchy:**
1. `IrcChannelConfig` - Per-group configuration (mention requirements, tool policies, allow lists)
2. `IrcNickServConfig` - NickServ authentication configuration
3. `IrcAccountConfig` - Full account configuration (server, auth, security, features)
4. `IrcConfig` - Multi-account configuration with defaults
5. `CoreConfig` - Root config extended with IRC channel config
6. `IrcInboundMessage` - Inbound message structure with peer/group distinction
7. `IrcProbe` - Connection probe result with latency and server info

